            </p>
          </div>
        ) : (
          <div className="text-center py-32 bg-slate-950/30 border-2 border-dashed border-slate-800 rounded-3xl">
            <div className="inline-block p-6 bg-slate-900 rounded-full mb-4 opacity-40">
