                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M4 6h16M4 10h16M4 14h16M4 18h16" />
              </svg>
            </div>
            <p className="text-xl font-bold text-slate-500">請從上方選單選擇型號以展開零件明細</p>
          </div>
        )}
      </div>
    </div>
  );
};

