import React, { useState } from 'react';
import { PRODUCT_DATA } from '../constants';
import { MaterialPart } from '../types';

const MaterialPanel: React.FC = () => {
  const [selectedModelId, setSelectedModelId] = useState<string>('');
  const [modelQuantity, setModelQuantity] = useState<number>(1);
  const [copyFeedback, setCopyFeedback] = useState<boolean>(false);

  const selectedModel = PRODUCT_DATA.find(m => m.id === selectedModelId);

  const handleCopyAll = () => {
    if (!selectedModel) return;

    // 統一組合成多行規格字串：[規格] * [總量]
    const allSpecsText = selectedModel.parts
      .map(part => `${part.specs} * ${part.baseQty * modelQuantity}`)
      .join('\n');

    navigator.clipboard.writeText(allSpecsText).then(() => {
      setCopyFeedback(true);
      setTimeout(() => setCopyFeedback(false), 2000);
    });
  };

  return (
    <div className="bg-slate-900 rounded-3xl shadow-2xl border border-slate-800 p-6 max-w-5xl mx-auto overflow-hidden">
      <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4">
        <h2 className="text-2xl font-bold text-white flex items-center">
          <span className="bg-indigo-600/20 text-indigo-400 p-2 rounded-xl mr-3 border border-indigo-500/20">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
            </svg>
          </span>
          叫料軟體
        </h2>

        <div className="flex items-center bg-slate-800/50 p-2 rounded-2xl border border-slate-700/50">
          <span className="text-xs font-black text-slate-500 mr-3 px-2">型號需求數量:</span>
          <div className="flex items-center bg-slate-900 rounded-xl p-1 border border-slate-700 shadow-inner">
            <button 
              onClick={() => setModelQuantity(Math.max(1, modelQuantity - 1))} 
              className="w-10 h-10 flex items-center justify-center text-slate-400 hover:text-white transition-colors"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 12H4" />
              </svg>
            </button>
            <input 
              type="number" 
              value={modelQuantity} 
              onChange={(e) => setModelQuantity(Number(e.target.value))}
              className="w-16 bg-transparent text-center font-black text-indigo-400 text-xl focus:outline-none"
            />
            <button 
              onClick={() => setModelQuantity(modelQuantity + 1)} 
              className="w-10 h-10 flex items-center justify-center text-slate-400 hover:text-white transition-colors"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
              </svg>
            </button>
          </div>
        </div>
      </div>

      <div className="space-y-6">
        <div>
          <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2 px-1">選擇產品型號 Select Model</label>
