            <option value="">-- 請選擇產品型號展開清單 --</option>
            {PRODUCT_DATA.map((model) => (
              <option key={model.id} value={model.id}>{model.modelName}</option>
            ))}
          </select>
        </div>

        {selectedModel ? (
          <div className="animate-in fade-in slide-in-from-bottom-6 duration-500">
            <div className="bg-slate-950/80 rounded-3xl border border-slate-800 overflow-hidden shadow-2xl">
              <div className="bg-indigo-600/10 px-6 py-4 border-b border-slate-800 flex justify-between items-center">
