                  <div className="text-xl font-black text-slate-400">{selectedModel.parts.length} 項</div>
                </div>
              </div>

              <div className="divide-y divide-slate-800">
                {selectedModel.parts.map((part) => (
                  <div key={part.id} className="grid grid-cols-1 md:grid-cols-2 group hover:bg-slate-800/40 transition-colors">
