                      <span className="text-[10px] text-indigo-500/60 font-mono mt-1">基準量: {part.baseQty}</span>
                    </div>

                    {/* 右方：規格與計算結果 */}
                    <div className="p-5 flex items-center justify-between bg-emerald-500/0 group-hover:bg-emerald-500/5 transition-colors">
                      <div className="flex flex-col">
                        <span className="text-[10px] text-slate-600 font-black uppercase mb-1">計算後規格 (規格 * 總量)</span>
                        <div className="flex items-baseline gap-2">
                          <span className="text-2xl font-mono font-black text-emerald-400">{part.specs}</span>
                          <span className="text-slate-500 font-mono">*</span>
                          <span className="text-2xl font-mono font-black text-indigo-400">{part.baseQty * modelQuantity}</span>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>

              {/* 底部統一複製按鈕 */}
              <div className="p-6 bg-slate-900/80 border-t border-slate-800">
                <button 
                  onClick={handleCopyAll}
