const CustomPanel: React.FC = () => {
  const [category, setCategory] = useState<string>('');
  const [length, setLength] = useState<string>('');
  const [depth, setDepth] = useState<string>('');
  const [price, setPrice] = useState<string>('');
  const [submittedOrders, setSubmittedOrders] = useState<CustomOrder[]>([]);
  const [copiedId, setCopiedId] = useState<string | null>(null);

  const handleClear = () => {
    setCategory('');
    setLength('');
    setDepth('');
    setPrice('');
  };

  const handleConfirm = () => {
    if (!category || !length || !depth || !price) {
      alert('請填寫完整訂做資訊！');
      return;
    }

    const newOrder: CustomOrder = {
      id: Date.now().toString(),
      category,
      length,
      depth,
      price,
      timestamp: new Date().toLocaleTimeString()
    };

    setSubmittedOrders([newOrder, ...submittedOrders]);
    handleClear();
  };

  const handleCopySpec = (order: CustomOrder) => {
    const specToCopy = `${order.length} * ${order.depth}`;
    navigator.clipboard.writeText(specToCopy).then(() => {
      setCopiedId(order.id);
      setTimeout(() => setCopiedId(null), 1500);
    });
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 max-w-7xl mx-auto">
